+    const int size = strlen(fmt) * 2;
+    char* buf = new char[strlen(fmt) * 2]; // reserve twice the length of fmt
+    va_list vl;
+    va_start(vl, fmt);
+    const int nsize = vsnprintf(buf, size, fmt, vl);
+    if (size <= nsize) { // resize string and try again
+        delete [] buf;
+        buf = new char[nsize];
+        vsprintf(buf, fmt, vl);
+    }
+    va_end(vl);
+    std::string s(buf, buf+nsize);
+    delete [] buf;
+    return s;
+}
